mapper.select:
SELECT * FROM poetry


        AND content LIKE CONCAT('%', #{query.keyword}, '%')


        AND dynasty = #{dynasty}


        AND author = #{query.author}


        AND id IN (
            SELECT poetry_id FROM poetry_tag 
            JOIN tag ON poetry_tag.tag_id = tag.id 
            WHERE tag.type = 'genre' AND tag.name = #{query.genre}
        )


        AND id IN (
            SELECT poetry_id FROM poetry_tag 
            JOIN tag ON poetry_tag.tag_id = tag.id 
            WHERE tag.type = 'theme' AND tag.name = #{query.theme}
        )


ORDER BY id DESC
